<?php
/**
 * Modul Infrastruktur Jaringan AppsBilling V3.
 * Seluruh data disimpan di tabel network_* agar terisolasi dari billing.
 */

function v3_network_pages(){
    return [
        'network-dashboard'=>'Ringkasan Infrastruktur',
        'network-odc'=>'Data ODC',
        'network-odp'=>'Data ODP',
        'network-jc'=>'Joint Closure',
        'network-cables'=>'Jalur Kabel',
        'network-splices'=>'Sambungan Core',
        'network-customers'=>'Penempatan Pelanggan',
    ];
}
function v3_network_title($page){ $p=v3_network_pages(); return $p[$page]??'Infrastruktur Jaringan'; }
function v3_network_statuses(){ return ['active'=>'Aktif','maintenance'=>'Perawatan','damaged'=>'Rusak','inactive'=>'Nonaktif']; }
function v3_network_status_badge($status){
    $map=['active'=>['Aktif','badge-success'],'maintenance'=>['Perawatan','badge-warning'],'damaged'=>['Rusak','badge-danger'],'inactive'=>['Nonaktif','badge-secondary'],'available'=>['Tersedia','badge-success'],'used'=>['Terpakai','badge-info'],'reserved'=>['Cadangan','badge-warning']];
    $v=$map[$status]??[ucfirst((string)$status),'badge-secondary']; return '<span class="badge '.$v[1].'">'.e($v[0]).'</span>';
}
function v3_network_node_type_for_page($page){ return ['network-odc'=>'ODC','network-odp'=>'ODP','network-jc'=>'JC'][$page]??''; }
function v3_network_clean_code($value){ return strtoupper(preg_replace('/[^A-Z0-9._\/-]+/','-',trim((string)$value))); }
function v3_network_point($lat,$lng,$combined=''){
    [$lat,$lng]=v3_parse_latlng($lat,$lng,$combined);
    if($lat==='' || $lng==='') throw new Exception('Koordinat tidak valid. Gunakan format latitude, longitude.');
    return [$lat,$lng];
}
function v3_network_node_label($r){ return trim(($r['node_code']??'').' · '.($r['name']??''),' ·'); }
function v3_network_endpoint_options($selected=0,$allowBlank=true){
    $rows=qall("SELECT id,node_type,node_code,name FROM network_nodes ORDER BY CASE node_type WHEN 'ODC' THEN 1 WHEN 'JC' THEN 2 ELSE 3 END,node_code");
    $html=$allowBlank?'<option value="">Pilih titik</option>':'';
    foreach($rows as $r) $html.='<option value="'.(int)$r['id'].'" '.((int)$selected===(int)$r['id']?'selected':'').'>'.e($r['node_type'].' · '.$r['node_code'].' · '.$r['name']).'</option>';
    return $html;
}
function v3_network_require_node($id,$type=''){
    $row=q1('SELECT * FROM network_nodes WHERE id=?',[(int)$id]);
    if(!$row || ($type!=='' && $row['node_type']!==$type)) throw new Exception('Titik jaringan tidak ditemukan atau jenisnya tidak sesuai.');
    return $row;
}
function v3_network_usage($nodeId){
    $node=q1('SELECT * FROM network_nodes WHERE id=?',[(int)$nodeId]); if(!$node) return 0;
    if($node['node_type']==='ODP') return (int)scalar("SELECT COUNT(*) FROM network_customer_placements WHERE odp_id=? AND status='active'",[(int)$nodeId]);
    if($node['node_type']==='ODC') return (int)scalar("SELECT COUNT(*) FROM network_nodes WHERE upstream_node_id=? AND status<>'inactive'",[(int)$nodeId]);
    return (int)scalar('SELECT COUNT(*) FROM network_splices WHERE joint_closure_id=?',[(int)$nodeId]);
}
function v3_network_validate_node_capacity($nodeId,$newCapacity){
    $used=v3_network_usage($nodeId); if($newCapacity<$used) throw new Exception('Kapasitas tidak boleh lebih kecil dari pemakaian saat ini ('.$used.').');
}
function v3_network_handle_post($action){
    if(strpos((string)$action,'network_')!==0) return false;
    require_non_crew(); $pdo=v3_db();
    $redirect=function($url){ if(defined('V3_NETWORK_TEST_MODE')) return $url; redirect($url); };
    if($action==='network_save_node'){
        $id=(int)($_POST['id']??0); $type=strtoupper(trim($_POST['node_type']??'')); if(!in_array($type,['ODC','ODP','JC'],true)) throw new Exception('Jenis titik jaringan tidak valid.');
        $code=v3_network_clean_code($_POST['node_code']??''); $name=trim($_POST['name']??''); $address=trim($_POST['address']??'');
        if($code==='' || $name==='') throw new Exception('ID dan nama titik wajib diisi.');
        $combined=trim($_POST['coordinates']??''); $lat=trim($_POST['latitude']??''); $lng=trim($_POST['longitude']??'');
        if($combined!=='' || $lat!=='' || $lng!=='') [$lat,$lng]=v3_network_point($lat,$lng,$combined); else {$lat='';$lng='';}
        $capacity=max(0,(int)($_POST['capacity']??0)); $status=$_POST['status']??'active'; if(!array_key_exists($status,v3_network_statuses())) $status='active';
        $upstream=(int)($_POST['upstream_node_id']??0); $upstreamPort=trim($_POST['upstream_port']??''); $notes=trim($_POST['notes']??'');
        if($upstream){ $up=v3_network_require_node($upstream); if($id && $upstream===$id) throw new Exception('Titik tidak boleh menjadi upstream dirinya sendiri.'); if($type==='ODC') throw new Exception('ODC tahap ini tidak memerlukan upstream internal.'); }
        if($id){
            $before=v3_network_require_node($id,$type); v3_network_validate_node_capacity($id,$capacity);
            $st=$pdo->prepare('UPDATE network_nodes SET node_code=?,name=?,address=?,latitude=?,longitude=?,capacity=?,status=?,upstream_node_id=?,upstream_port=?,notes=?,updated_at=CURRENT_TIMESTAMP WHERE id=? AND node_type=?');
            $st->execute([$code,$name,$address,$lat,$lng,$capacity,$status,$upstream?:null,$upstreamPort,$notes,$id,$type]);
        }else{
            $before=null; $st=$pdo->prepare('INSERT INTO network_nodes(node_type,node_code,name,address,latitude,longitude,capacity,status,upstream_node_id,upstream_port,notes,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)');
            $st->execute([$type,$code,$name,$address,$lat,$lng,$capacity,$status,$upstream?:null,$upstreamPort,$notes]); $id=(int)$pdo->lastInsertId();
        }
        $after=v3_network_require_node($id,$type); v3_log_activity($before?'update':'create','network_node',$id,v3_network_node_label($after),($before?'Mengubah ':'Menambah ').$type.' tanpa mengubah data billing.',$before,$after);
        $_SESSION['flash']=$type.' '.$code.' berhasil disimpan.'; return $redirect('index.php?page='.strtolower('network-'.$type));
    }
    if($action==='network_delete_node'){
        $id=(int)($_POST['id']??0); $old=v3_network_require_node($id); $refs=(int)scalar('SELECT COUNT(*) FROM network_nodes WHERE upstream_node_id=?',[$id])+(int)scalar('SELECT COUNT(*) FROM network_cable_routes WHERE start_node_id=? OR end_node_id=?',[$id,$id])+(int)scalar('SELECT COUNT(*) FROM network_splices WHERE joint_closure_id=? OR from_node_id=? OR to_node_id=?',[$id,$id,$id])+(int)scalar('SELECT COUNT(*) FROM network_customer_placements WHERE odp_id=?',[$id]);
        if($refs>0) throw new Exception('Titik masih memiliki '.$refs.' relasi. Pindahkan/hapus relasinya lebih dulu agar topologi tidak putus.');
        $pdo->prepare('DELETE FROM network_nodes WHERE id=?')->execute([$id]); v3_log_activity('delete','network_node',$id,v3_network_node_label($old),'Menghapus titik jaringan tanpa mengubah billing.',$old,null);
        $_SESSION['flash']=$old['node_type'].' '.$old['node_code'].' dihapus.'; return $redirect('index.php?page='.strtolower('network-'.$old['node_type']));
    }
    if($action==='network_save_cable'){
        $id=(int)($_POST['id']??0); $before=$id?q1('SELECT * FROM network_cable_routes WHERE id=?',[$id]):null;
        $code=v3_network_clean_code($_POST['route_code']??''); $name=trim($_POST['name']??''); $start=(int)($_POST['start_node_id']??0); $end=(int)($_POST['end_node_id']??0);
        if($code===''||$name===''||!$start||!$end||$start===$end) throw new Exception('ID, nama, titik awal, dan titik akhir jalur wajib valid.'); v3_network_require_node($start); v3_network_require_node($end);
        $core=max(1,(int)($_POST['core_count']??1)); if($id){$used=(int)scalar('SELECT COALESCE(MAX(MAX(incoming_core,outgoing_core)),0) FROM network_splices WHERE incoming_route_id=? OR outgoing_route_id=?',[$id,$id]); if($core<$used) throw new Exception('Jumlah core tidak boleh lebih kecil dari core sambungan tertinggi ('.$used.').');}
        $data=[$code,$name,trim($_POST['cable_type']??'Fiber Optic'),$core,max(0,(float)($_POST['length_m']??0)),$_POST['status']??'active',$start,$end,trim($_POST['path_note']??''),trim($_POST['notes']??'')];
        if($id){$data[]=$id;$pdo->prepare('UPDATE network_cable_routes SET route_code=?,name=?,cable_type=?,core_count=?,length_m=?,status=?,start_node_id=?,end_node_id=?,path_note=?,notes=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO network_cable_routes(route_code,name,cable_type,core_count,length_m,status,start_node_id,end_node_id,path_note,notes,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)')->execute($data);$id=(int)$pdo->lastInsertId();}
        $after=q1('SELECT * FROM network_cable_routes WHERE id=?',[$id]); v3_log_activity($before?'update':'create','network_cable_route',$id,$after['route_code'].' · '.$after['name'],($before?'Mengubah':'Menambah').' jalur kabel terisolasi dari billing.',$before,$after);
        $_SESSION['flash']='Jalur kabel '.$code.' tersimpan.'; return $redirect('index.php?page=network-cables');
    }
    if($action==='network_delete_cable'){
        $id=(int)($_POST['id']??0); $old=q1('SELECT * FROM network_cable_routes WHERE id=?',[$id]); if(!$old) throw new Exception('Jalur kabel tidak ditemukan.');
        $refs=(int)scalar('SELECT COUNT(*) FROM network_splices WHERE incoming_route_id=? OR outgoing_route_id=?',[$id,$id]); if($refs) throw new Exception('Jalur masih dipakai pada '.$refs.' sambungan core. Hapus sambungan lebih dahulu.');
        $pdo->prepare('DELETE FROM network_cable_routes WHERE id=?')->execute([$id]); v3_log_activity('delete','network_cable_route',$id,$old['route_code'],'Menghapus jalur kabel.',$old,null); $_SESSION['flash']='Jalur kabel dihapus.'; return $redirect('index.php?page=network-cables');
    }
    if($action==='network_save_splice'){
        $id=(int)($_POST['id']??0); $before=$id?q1('SELECT * FROM network_splices WHERE id=?',[$id]):null; $jc=(int)($_POST['joint_closure_id']??0); v3_network_require_node($jc,'JC');
        $inRoute=(int)($_POST['incoming_route_id']??0); $outRoute=(int)($_POST['outgoing_route_id']??0); $inCore=max(1,(int)($_POST['incoming_core']??0)); $outCore=max(1,(int)($_POST['outgoing_core']??0));
        $rin=q1('SELECT * FROM network_cable_routes WHERE id=?',[$inRoute]); $rout=q1('SELECT * FROM network_cable_routes WHERE id=?',[$outRoute]); if(!$rin||!$rout) throw new Exception('Jalur kabel masuk dan keluar wajib dipilih.'); if($inRoute===$outRoute && $inCore===$outCore) throw new Exception('Core masuk dan keluar tidak boleh identik.'); if($inCore>(int)$rin['core_count']||$outCore>(int)$rout['core_count']) throw new Exception('Nomor core melebihi kapasitas jalur kabel.');
        $from=(int)($_POST['from_node_id']??0); $to=(int)($_POST['to_node_id']??0); if($from)v3_network_require_node($from);if($to)v3_network_require_node($to);
        $data=[$jc,$inRoute,$inCore,trim($_POST['incoming_color']??''),$outRoute,$outCore,trim($_POST['outgoing_color']??''),$from?:null,$to?:null,$_POST['usage_status']??'used',trim($_POST['signal_note']??''),trim($_POST['notes']??'')];
        if($id){$data[]=$id;$pdo->prepare('UPDATE network_splices SET joint_closure_id=?,incoming_route_id=?,incoming_core=?,incoming_color=?,outgoing_route_id=?,outgoing_core=?,outgoing_color=?,from_node_id=?,to_node_id=?,usage_status=?,signal_note=?,notes=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO network_splices(joint_closure_id,incoming_route_id,incoming_core,incoming_color,outgoing_route_id,outgoing_core,outgoing_color,from_node_id,to_node_id,usage_status,signal_note,notes,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)')->execute($data);$id=(int)$pdo->lastInsertId();}
        $after=q1('SELECT * FROM network_splices WHERE id=?',[$id]); v3_log_activity($before?'update':'create','network_splice',$id,'Sambungan core #'.$id,($before?'Mengubah':'Menambah').' sambungan core di Joint Closure.',$before,$after); $_SESSION['flash']='Sambungan core berhasil disimpan.'; return $redirect('index.php?page=network-splices');
    }
    if($action==='network_delete_splice'){
        $id=(int)($_POST['id']??0); $old=q1('SELECT * FROM network_splices WHERE id=?',[$id]); if(!$old) throw new Exception('Sambungan core tidak ditemukan.'); $pdo->prepare('DELETE FROM network_splices WHERE id=?')->execute([$id]); v3_log_activity('delete','network_splice',$id,'Sambungan core #'.$id,'Menghapus sambungan core.',$old,null); $_SESSION['flash']='Sambungan core dihapus.'; return $redirect('index.php?page=network-splices');
    }
    if($action==='network_save_customer_placement'){
        $id=(int)($_POST['id']??0); $before=$id?q1('SELECT * FROM network_customer_placements WHERE id=?',[$id]):null; $customer=(int)($_POST['customer_id']??0); if(!q1('SELECT id FROM customers WHERE id=?',[$customer])) throw new Exception('Pelanggan tidak ditemukan.');
        $odp=(int)($_POST['odp_id']??0); $odpRow=v3_network_require_node($odp,'ODP'); $port=max(1,(int)($_POST['port_no']??0)); if($port>(int)$odpRow['capacity']) throw new Exception('Nomor port melebihi kapasitas ODP ('.(int)$odpRow['capacity'].').');
        $dup=q1('SELECT id FROM network_customer_placements WHERE odp_id=? AND port_no=? AND status=? AND id<>?',[$odp,$port,'active',$id]); if($dup) throw new Exception('Port '.$port.' pada '.$odpRow['node_code'].' sudah terpakai.');
        $data=[$customer,$odp,$port,trim($_POST['drop_cable_label']??''),$_POST['status']??'active',trim($_POST['installed_at']??date('Y-m-d')),trim($_POST['notes']??'')];
        if($id){$data[]=$id;$pdo->prepare('UPDATE network_customer_placements SET customer_id=?,odp_id=?,port_no=?,drop_cable_label=?,status=?,installed_at=?,notes=?,updated_at=CURRENT_TIMESTAMP WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO network_customer_placements(customer_id,odp_id,port_no,drop_cable_label,status,installed_at,notes,updated_at) VALUES(?,?,?,?,?,?,?,CURRENT_TIMESTAMP)')->execute($data);$id=(int)$pdo->lastInsertId();}
        $after=q1('SELECT * FROM network_customer_placements WHERE id=?',[$id]); v3_log_activity($before?'update':'create','network_customer_placement',$id,'Penempatan pelanggan #'.$customer,($before?'Mengubah':'Menambah').' relasi pelanggan ke ODP tanpa mengubah profil billing pelanggan.',$before,$after); $_SESSION['flash']='Penempatan pelanggan ke ODP tersimpan.'; return $redirect('index.php?page=network-customers');
    }
    if($action==='network_delete_customer_placement'){
        $id=(int)($_POST['id']??0); $old=q1('SELECT * FROM network_customer_placements WHERE id=?',[$id]); if(!$old) throw new Exception('Penempatan pelanggan tidak ditemukan.'); $pdo->prepare('DELETE FROM network_customer_placements WHERE id=?')->execute([$id]); v3_log_activity('delete','network_customer_placement',$id,'Penempatan pelanggan #'.$old['customer_id'],'Melepas relasi pelanggan dari ODP tanpa menghapus pelanggan.',$old,null); $_SESSION['flash']='Pelanggan dilepas dari ODP. Data pelanggan tetap utuh.'; return $redirect('index.php?page=network-customers');
    }
    return true;
}

function v3_network_delete_form($action,$id,$label='Hapus'){
    return '<form method="post" class="d-inline" onsubmit="return confirm(\'Yakin '.$label.'? Data billing tidak akan dihapus.\')"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="'.e($action).'"><input type="hidden" name="id" value="'.(int)$id.'"><button class="btn btn-danger btn-sm">'.$label.'</button></form>';
}
function v3_network_coordinates_input($row=[]){
    $v=trim(($row['latitude']??'').(($row['latitude']??'')!==''&&($row['longitude']??'')!==''?', ':'').($row['longitude']??''));
    return '<label>Titik koordinat</label><input class="form-control" name="coordinates" value="'.e($v).'" placeholder="-8.123456, 112.123456"><small class="text-muted">Latitude, longitude. Jika kosong, tombol Google Maps tidak ditampilkan.</small>';
}
function v3_network_render_dashboard(){
    $counts=[]; foreach(['ODC','ODP','JC'] as $t)$counts[$t]=(int)scalar('SELECT COUNT(*) FROM network_nodes WHERE node_type=?',[$t]);
    $routes=(int)scalar('SELECT COUNT(*) FROM network_cable_routes'); $splices=(int)scalar('SELECT COUNT(*) FROM network_splices'); $placed=(int)scalar("SELECT COUNT(*) FROM network_customer_placements WHERE status='active'"); $customers=(int)scalar("SELECT COUNT(*) FROM customers WHERE customer_status='active'");
    $capacity=(int)scalar("SELECT COALESCE(SUM(capacity),0) FROM network_nodes WHERE node_type='ODP' AND status='active'"); $free=max(0,$capacity-$placed); $pct=$capacity>0?min(100,round($placed/$capacity*100,1)):0;
    echo '<div class="network-hero"><div><span class="network-kicker"><i class="fas fa-project-diagram"></i> Operasional jaringan terisolasi</span><h2>Infrastruktur dari ODC sampai pelanggan</h2><p>Catat aset, jalur kabel, sambungan core, kapasitas port, dan posisi pelanggan tanpa mengubah invoice, pembayaran, atau profil billing.</p></div><div class="network-hero-actions"><a class="btn btn-light" href="'.page_url('network-odp').'"><i class="fas fa-plus"></i> Tambah ODP</a><a class="btn btn-warning" href="'.page_url('network-splices').'"><i class="fas fa-link"></i> Catat sambungan</a></div></div>';
    echo '<div class="network-stat-grid"><a href="'.page_url('network-odc').'" class="network-stat"><i class="fas fa-building"></i><span>ODC</span><b>'.$counts['ODC'].'</b><small>Titik distribusi utama</small></a><a href="'.page_url('network-odp').'" class="network-stat"><i class="fas fa-box-open"></i><span>ODP</span><b>'.$counts['ODP'].'</b><small>'.$placed.' pelanggan ditempatkan</small></a><a href="'.page_url('network-jc').'" class="network-stat"><i class="fas fa-code-branch"></i><span>Joint Closure</span><b>'.$counts['JC'].'</b><small>'.$splices.' sambungan core</small></a><a href="'.page_url('network-cables').'" class="network-stat"><i class="fas fa-route"></i><span>Jalur kabel</span><b>'.$routes.'</b><small>Rute antar titik</small></a></div>';
    echo '<div class="row"><div class="col-lg-7"><div class="card network-card"><div class="card-header"><h3 class="card-title">Kapasitas ODP aktif</h3><a class="btn btn-info btn-sm" href="'.page_url('network-customers').'">Kelola pelanggan</a></div><div class="card-body"><div class="network-capacity-head"><div><b>'.$placed.' / '.$capacity.' port</b><span>'.$free.' port masih tersedia</span></div><strong>'.$pct.'%</strong></div><div class="network-capacity-bar"><i style="width:'.$pct.'%"></i></div><p class="mini-note">Port aktif dihitung dari penempatan pelanggan. Sistem menolak port ganda dan nomor port yang melebihi kapasitas ODP.</p></div></div></div><div class="col-lg-5"><div class="card network-card"><div class="card-header"><h3 class="card-title">Cakupan pelanggan</h3></div><div class="card-body"><div class="network-coverage"><b>'.$placed.'</b><span>dari '.$customers.' pelanggan aktif sudah memiliki ODP</span></div><a class="btn btn-outline-info btn-block" href="'.page_url('network-customers').'">Lengkapi penempatan</a></div></div></div></div>';
    $recent=qall("SELECT 'node' kind,node_type label,node_code code,name,updated_at FROM network_nodes UNION ALL SELECT 'cable','KABEL',route_code,name,updated_at FROM network_cable_routes ORDER BY updated_at DESC LIMIT 8");
    echo '<div class="card network-card"><div class="card-header"><h3 class="card-title">Pembaruan aset terakhir</h3></div><div class="card-body"><div class="network-activity-list">'; foreach($recent as $r)echo '<div><span>'.e($r['label']).'</span><b>'.e($r['code'].' · '.$r['name']).'</b><small>'.e($r['updated_at']?:'-').'</small></div>'; if(!$recent)echo '<div class="activity-empty">Belum ada data jaringan. Mulai dari ODC atau ODP.</div>'; echo '</div></div></div>';
}
function v3_network_render_nodes($page){
    $type=v3_network_node_type_for_page($page); $editId=(int)($_GET['edit']??0); $edit=$editId?q1('SELECT * FROM network_nodes WHERE id=? AND node_type=?',[$editId,$type]):[]; $statuses=v3_network_statuses();
    echo '<div class="network-page-head"><div><span class="network-kicker">Master aset '.$type.'</span><h2>'.v3_network_title($page).'</h2><p>'.($type==='JC'?'Joint Closure menjadi titik fisik sambungan core antarjalur kabel.':($type==='ODP'?'ODP adalah terminasi pelanggan dengan kontrol port dan kapasitas.':'ODC menjadi sumber distribusi untuk ODP atau jalur berikutnya.')).'</p></div><a class="btn btn-secondary" href="'.page_url('network-dashboard').'">Ringkasan</a></div>';
    echo '<div class="row"><div class="col-xl-4"><div class="card network-card network-form-card"><div class="card-header"><h3 class="card-title">'.($edit?'Edit':'Tambah').' '.$type.'</h3></div><div class="card-body"><form method="post"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="network_save_node"><input type="hidden" name="node_type" value="'.$type.'"><input type="hidden" name="id" value="'.(int)($edit['id']??0).'"><div class="form-group"><label>ID '.$type.' custom</label><input class="form-control" name="node_code" value="'.e($edit['node_code']??'').'" placeholder="'.$type.'-DSG-001" required></div><div class="form-group"><label>Nama '.$type.'</label><input class="form-control" name="name" value="'.e($edit['name']??'').'" placeholder="Nama area / cluster" required></div><div class="form-group"><label>Alamat / lokasi</label><textarea class="form-control" name="address" rows="2">'.e($edit['address']??'').'</textarea></div><div class="form-group">'.v3_network_coordinates_input($edit).'</div><div class="row"><div class="col-6"><div class="form-group"><label>Kapasitas '.($type==='ODP'?'port':($type==='ODC'?'distribusi':'sambungan')).'</label><input class="form-control" type="number" min="0" name="capacity" value="'.e($edit['capacity']??($type==='ODP'?8:0)).'"></div></div><div class="col-6"><div class="form-group"><label>Status</label><select class="form-control" name="status">'; foreach($statuses as $k=>$v)echo '<option value="'.$k.'" '.(($edit['status']??'active')===$k?'selected':'').'>'.e($v).'</option>'; echo '</select></div></div></div>';
    if($type!=='ODC'){echo '<div class="form-group"><label>Upstream / sumber sebelumnya</label><select class="form-control" name="upstream_node_id">'.v3_network_endpoint_options((int)($edit['upstream_node_id']??0)).'</select></div><div class="form-group"><label>Port / label upstream</label><input class="form-control" name="upstream_port" value="'.e($edit['upstream_port']??'').'" placeholder="Contoh: Port 2 / Core 7"></div>';}
    echo '<div class="form-group"><label>Catatan</label><textarea class="form-control" name="notes" rows="3">'.e($edit['notes']??'').'</textarea></div><button class="btn btn-info">Simpan '.$type.'</button> '.($edit?'<a class="btn btn-secondary" href="'.page_url($page).'">Batal</a>':'').'</form></div></div></div><div class="col-xl-8"><div class="card network-card"><div class="card-header"><h3 class="card-title">Daftar '.$type.'</h3><span class="badge badge-info">'.(int)scalar('SELECT COUNT(*) FROM network_nodes WHERE node_type=?',[$type]).' titik</span></div><div class="card-body"><div class="table-wrap"><table class="table table-striped network-table"><thead><tr><th>ID</th><th>Nama & lokasi</th><th>Upstream</th><th>Kapasitas</th><th>Status</th><th>Koordinat</th><th>Aksi</th></tr></thead><tbody>';
    $rows=qall('SELECT n.*,u.node_code upstream_code,u.name upstream_name FROM network_nodes n LEFT JOIN network_nodes u ON u.id=n.upstream_node_id WHERE n.node_type=? ORDER BY n.node_code',[$type]); foreach($rows as $r){$used=v3_network_usage($r['id']);$map=($r['latitude']!==''&&$r['longitude']!=='')?'<a target="_blank" rel="noopener" href="'.e(v3_google_maps_url($r['latitude'],$r['longitude'])).'" class="btn btn-success btn-sm"><i class="fas fa-map-marker-alt"></i> Maps</a>':'<span class="text-muted">Belum ada</span>';echo '<tr><td><b>'.e($r['node_code']).'</b></td><td><b>'.e($r['name']).'</b><small>'.e($r['address']?:'-').'</small></td><td>'.e($r['upstream_code']?:'-').'<small>'.e($r['upstream_port']?:'').'</small></td><td><b>'.$used.' / '.(int)$r['capacity'].'</b><small>'.max(0,(int)$r['capacity']-$used).' tersedia</small></td><td>'.v3_network_status_badge($r['status']).'</td><td>'.$map.'</td><td><a class="btn btn-info btn-sm" href="'.page_url($page,['edit'=>$r['id']]).'">Edit</a> '.v3_network_delete_form('network_delete_node',$r['id'],'Hapus').'</td></tr>';} if(!$rows)echo '<tr><td colspan="7" class="text-center text-muted">Belum ada data '.$type.'.</td></tr>'; echo '</tbody></table></div></div></div></div></div>';
}
function v3_network_render_cables(){
    $editId=(int)($_GET['edit']??0);$eRow=$editId?q1('SELECT * FROM network_cable_routes WHERE id=?',[$editId]):[];
    echo '<div class="network-page-head"><div><span class="network-kicker">Rute fisik fiber</span><h2>Jalur Kabel</h2><p>Satu jalur menghubungkan dua titik jaringan dan memiliki jumlah core yang menjadi batas sambungan.</p></div><a class="btn btn-secondary" href="'.page_url('network-dashboard').'">Ringkasan</a></div><div class="row"><div class="col-xl-4"><div class="card network-card network-form-card"><div class="card-header"><h3 class="card-title">'.($eRow?'Edit':'Tambah').' jalur</h3></div><div class="card-body"><form method="post"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="network_save_cable"><input type="hidden" name="id" value="'.(int)($eRow['id']??0).'"><div class="form-group"><label>ID jalur custom</label><input class="form-control" name="route_code" value="'.e($eRow['route_code']??'').'" placeholder="CBL-DSG-001" required></div><div class="form-group"><label>Nama jalur</label><input class="form-control" name="name" value="'.e($eRow['name']??'').'" placeholder="Feeder ODC ke Area Barat" required></div><div class="row"><div class="col-7"><div class="form-group"><label>Jenis kabel</label><input class="form-control" name="cable_type" value="'.e($eRow['cable_type']??'Fiber Optic').'" placeholder="FO 24 Core"></div></div><div class="col-5"><div class="form-group"><label>Jumlah core</label><input class="form-control" type="number" min="1" name="core_count" value="'.e($eRow['core_count']??12).'" required></div></div></div><div class="row"><div class="col-6"><div class="form-group"><label>Panjang (meter)</label><input class="form-control" type="number" min="0" step="0.1" name="length_m" value="'.e($eRow['length_m']??0).'"></div></div><div class="col-6"><div class="form-group"><label>Status</label><select class="form-control" name="status">';foreach(v3_network_statuses() as $k=>$v)echo '<option value="'.$k.'" '.(($eRow['status']??'active')===$k?'selected':'').'>'.e($v).'</option>';echo '</select></div></div></div><div class="form-group"><label>Titik awal</label><select class="form-control" name="start_node_id" required>'.v3_network_endpoint_options((int)($eRow['start_node_id']??0)).'</select></div><div class="form-group"><label>Titik akhir</label><select class="form-control" name="end_node_id" required>'.v3_network_endpoint_options((int)($eRow['end_node_id']??0)).'</select></div><div class="form-group"><label>Catatan jalur / patokan</label><input class="form-control" name="path_note" value="'.e($eRow['path_note']??'').'" placeholder="Via tiang, ruas jalan, arah tarikan"></div><div class="form-group"><label>Catatan teknis</label><textarea class="form-control" name="notes" rows="2">'.e($eRow['notes']??'').'</textarea></div><button class="btn btn-info">Simpan jalur</button> '.($eRow?'<a class="btn btn-secondary" href="'.page_url('network-cables').'">Batal</a>':'').'</form></div></div></div><div class="col-xl-8"><div class="card network-card"><div class="card-header"><h3 class="card-title">List jalur kabel</h3></div><div class="card-body"><div class="table-wrap"><table class="table table-striped network-table"><thead><tr><th>ID / nama</th><th>Lintasan</th><th>Kabel</th><th>Panjang</th><th>Sambungan</th><th>Status</th><th>Aksi</th></tr></thead><tbody>';
    $rows=qall('SELECT r.*,a.node_code start_code,b.node_code end_code,(SELECT COUNT(*) FROM network_splices s WHERE s.incoming_route_id=r.id OR s.outgoing_route_id=r.id) splice_count FROM network_cable_routes r JOIN network_nodes a ON a.id=r.start_node_id JOIN network_nodes b ON b.id=r.end_node_id ORDER BY r.route_code');foreach($rows as $r)echo '<tr><td><b>'.e($r['route_code']).'</b><small>'.e($r['name']).'</small></td><td>'.e($r['start_code']).' <i class="fas fa-long-arrow-alt-right"></i> '.e($r['end_code']).'<small>'.e($r['path_note']?:'-').'</small></td><td><b>'.(int)$r['core_count'].' core</b><small>'.e($r['cable_type']).'</small></td><td>'.number_format((float)$r['length_m'],1,',','.').' m</td><td>'.(int)$r['splice_count'].' core</td><td>'.v3_network_status_badge($r['status']).'</td><td><a class="btn btn-info btn-sm" href="'.page_url('network-cables',['edit'=>$r['id']]).'">Edit</a> '.v3_network_delete_form('network_delete_cable',$r['id'],'Hapus').'</td></tr>';if(!$rows)echo '<tr><td colspan="7" class="text-center text-muted">Belum ada jalur kabel.</td></tr>';echo '</tbody></table></div></div></div></div></div>';
}
function v3_network_route_options($selected=0){$rows=qall('SELECT * FROM network_cable_routes ORDER BY route_code');$h='<option value="">Pilih jalur</option>';foreach($rows as $r)$h.='<option value="'.(int)$r['id'].'" '.((int)$selected===(int)$r['id']?'selected':'').'>'.e($r['route_code'].' · '.$r['name'].' · '.$r['core_count'].' core').'</option>';return $h;}
function v3_network_render_splices(){
    $editId=(int)($_GET['edit']??0);$eRow=$editId?q1('SELECT * FROM network_splices WHERE id=?',[$editId]):[];$jcs=qall("SELECT * FROM network_nodes WHERE node_type='JC' ORDER BY node_code");
    echo '<div class="network-page-head"><div><span class="network-kicker">List titik sambungan kabel</span><h2>Sambungan Core</h2><p>Setiap baris menjelaskan core kabel masuk disambung ke core kabel keluar di Joint Closure tertentu.</p></div><a class="btn btn-secondary" href="'.page_url('network-dashboard').'">Ringkasan</a></div><div class="row"><div class="col-xl-4"><div class="card network-card network-form-card"><div class="card-header"><h3 class="card-title">'.($eRow?'Edit':'Tambah').' sambungan</h3></div><div class="card-body"><div class="alert alert-info"><b>Gambaran praktis:</b> pilih Joint Closure, kabel/core yang masuk, lalu kabel/core tujuan. Warna core opsional agar teknisi mudah mencocokkan kondisi lapangan.</div><form method="post"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="network_save_splice"><input type="hidden" name="id" value="'.(int)($eRow['id']??0).'"><div class="form-group"><label>Joint Closure</label><select class="form-control" name="joint_closure_id" required><option value="">Pilih JC</option>';foreach($jcs as $r)echo '<option value="'.(int)$r['id'].'" '.((int)($eRow['joint_closure_id']??0)===(int)$r['id']?'selected':'').'>'.e($r['node_code'].' · '.$r['name']).'</option>';echo '</select></div><div class="network-splice-pair"><div><b>CORE MASUK</b><div class="form-group"><label>Jalur kabel</label><select class="form-control" name="incoming_route_id" required>'.v3_network_route_options((int)($eRow['incoming_route_id']??0)).'</select></div><div class="row"><div class="col-6"><div class="form-group"><label>No. core</label><input class="form-control" type="number" min="1" name="incoming_core" value="'.e($eRow['incoming_core']??1).'" required></div></div><div class="col-6"><div class="form-group"><label>Warna</label><input class="form-control" name="incoming_color" value="'.e($eRow['incoming_color']??'').'"></div></div></div></div><i class="fas fa-link"></i><div><b>CORE KELUAR</b><div class="form-group"><label>Jalur kabel</label><select class="form-control" name="outgoing_route_id" required>'.v3_network_route_options((int)($eRow['outgoing_route_id']??0)).'</select></div><div class="row"><div class="col-6"><div class="form-group"><label>No. core</label><input class="form-control" type="number" min="1" name="outgoing_core" value="'.e($eRow['outgoing_core']??1).'" required></div></div><div class="col-6"><div class="form-group"><label>Warna</label><input class="form-control" name="outgoing_color" value="'.e($eRow['outgoing_color']??'').'"></div></div></div></div></div><div class="form-group"><label>Dari titik</label><select class="form-control" name="from_node_id">'.v3_network_endpoint_options((int)($eRow['from_node_id']??0)).'</select></div><div class="form-group"><label>Menuju titik</label><select class="form-control" name="to_node_id">'.v3_network_endpoint_options((int)($eRow['to_node_id']??0)).'</select></div><div class="row"><div class="col-5"><div class="form-group"><label>Status</label><select class="form-control" name="usage_status"><option value="used" '.(($eRow['usage_status']??'used')==='used'?'selected':'').'>Terpakai</option><option value="available" '.(($eRow['usage_status']??'')==='available'?'selected':'').'>Tersedia</option><option value="reserved" '.(($eRow['usage_status']??'')==='reserved'?'selected':'').'>Cadangan</option></select></div></div><div class="col-7"><div class="form-group"><label>Catatan sinyal</label><input class="form-control" name="signal_note" value="'.e($eRow['signal_note']??'').'" placeholder="Redaman / hasil OTDR"></div></div></div><div class="form-group"><label>Catatan teknis</label><textarea class="form-control" name="notes" rows="2">'.e($eRow['notes']??'').'</textarea></div><button class="btn btn-warning">Simpan sambungan</button> '.($eRow?'<a class="btn btn-secondary" href="'.page_url('network-splices').'">Batal</a>':'').'</form></div></div></div><div class="col-xl-8"><div class="card network-card"><div class="card-header"><h3 class="card-title">List sambungan core</h3><span class="badge badge-warning">'.(int)scalar('SELECT COUNT(*) FROM network_splices').' sambungan</span></div><div class="card-body"><div class="table-wrap"><table class="table table-striped network-table"><thead><tr><th>Joint Closure</th><th>Core masuk</th><th>Core keluar</th><th>Arah</th><th>Status / sinyal</th><th>Aksi</th></tr></thead><tbody>';
    $rows=qall('SELECT s.*,jc.node_code jc_code,ri.route_code in_route,ro.route_code out_route,fn.node_code from_code,tn.node_code to_code FROM network_splices s JOIN network_nodes jc ON jc.id=s.joint_closure_id JOIN network_cable_routes ri ON ri.id=s.incoming_route_id JOIN network_cable_routes ro ON ro.id=s.outgoing_route_id LEFT JOIN network_nodes fn ON fn.id=s.from_node_id LEFT JOIN network_nodes tn ON tn.id=s.to_node_id ORDER BY jc.node_code,s.incoming_route_id,s.incoming_core');foreach($rows as $r)echo '<tr><td><b>'.e($r['jc_code']).'</b><small>#'.(int)$r['id'].'</small></td><td><b>'.e($r['in_route']).' / Core '.(int)$r['incoming_core'].'</b><small>'.e($r['incoming_color']?:'Warna belum diisi').'</small></td><td><b>'.e($r['out_route']).' / Core '.(int)$r['outgoing_core'].'</b><small>'.e($r['outgoing_color']?:'Warna belum diisi').'</small></td><td>'.e($r['from_code']?:'-').' <i class="fas fa-arrow-right"></i> '.e($r['to_code']?:'-').'</td><td>'.v3_network_status_badge($r['usage_status']).'<small>'.e($r['signal_note']?:'-').'</small></td><td><a class="btn btn-info btn-sm" href="'.page_url('network-splices',['edit'=>$r['id']]).'">Edit</a> '.v3_network_delete_form('network_delete_splice',$r['id'],'Hapus').'</td></tr>';if(!$rows)echo '<tr><td colspan="6" class="text-center text-muted">Belum ada sambungan core. Buat JC dan jalur kabel lebih dulu.</td></tr>';echo '</tbody></table></div></div></div></div></div>';
}
function v3_network_render_customers(){
    $editId=(int)($_GET['edit']??0);$eRow=$editId?q1('SELECT * FROM network_customer_placements WHERE id=?',[$editId]):[];$odps=qall("SELECT n.*,(SELECT COUNT(*) FROM network_customer_placements p WHERE p.odp_id=n.id AND p.status='active') used FROM network_nodes n WHERE n.node_type='ODP' ORDER BY n.node_code");$customers=qall("SELECT c.id,c.customer_code,c.name,c.address FROM customers c LEFT JOIN network_customer_placements p ON p.customer_id=c.id WHERE p.id IS NULL OR p.id=? ORDER BY c.name LIMIT 6000",[$editId]);
    echo '<div class="network-page-head"><div><span class="network-kicker">Relasi teknis tambahan</span><h2>Penempatan Pelanggan</h2><p>Hubungkan pelanggan ke ODP dan port. Data customer, paket, invoice, dan pembayaran tidak diubah.</p></div><a class="btn btn-secondary" href="'.page_url('network-dashboard').'">Ringkasan</a></div><div class="row"><div class="col-xl-4"><div class="card network-card network-form-card"><div class="card-header"><h3 class="card-title">'.($eRow?'Edit':'Tempatkan').' pelanggan</h3></div><div class="card-body"><form method="post"><input type="hidden" name="csrf" value="'.csrf_token().'"><input type="hidden" name="action" value="network_save_customer_placement"><input type="hidden" name="id" value="'.(int)($eRow['id']??0).'"><div class="form-group"><label>Pelanggan</label><select class="form-control" name="customer_id" required><option value="">Pilih pelanggan</option>';foreach($customers as $c)echo '<option value="'.(int)$c['id'].'" '.((int)($eRow['customer_id']??0)===(int)$c['id']?'selected':'').'>'.e($c['customer_code'].' · '.$c['name'].' · '.$c['address']).'</option>';echo '</select></div><div class="form-group"><label>ODP tujuan</label><select class="form-control" name="odp_id" required><option value="">Pilih ODP</option>';foreach($odps as $o)echo '<option value="'.(int)$o['id'].'" '.((int)($eRow['odp_id']??0)===(int)$o['id']?'selected':'').'>'.e($o['node_code'].' · '.$o['name'].' · '.$o['used'].'/'.$o['capacity'].' port').'</option>';echo '</select></div><div class="row"><div class="col-6"><div class="form-group"><label>Nomor port</label><input class="form-control" type="number" min="1" name="port_no" value="'.e($eRow['port_no']??1).'" required></div></div><div class="col-6"><div class="form-group"><label>Status</label><select class="form-control" name="status"><option value="active" '.(($eRow['status']??'active')==='active'?'selected':'').'>Aktif</option><option value="inactive" '.(($eRow['status']??'')==='inactive'?'selected':'').'>Nonaktif</option></select></div></div></div><div class="form-group"><label>Label drop cable</label><input class="form-control" name="drop_cable_label" value="'.e($eRow['drop_cable_label']??'').'" placeholder="DROP-DNxxxx / label lapangan"></div><div class="form-group"><label>Tanggal pemasangan</label><input class="form-control" type="date" name="installed_at" value="'.e($eRow['installed_at']??date('Y-m-d')).'"></div><div class="form-group"><label>Catatan</label><textarea class="form-control" name="notes" rows="2">'.e($eRow['notes']??'').'</textarea></div><button class="btn btn-info">Simpan penempatan</button> '.($eRow?'<a class="btn btn-secondary" href="'.page_url('network-customers').'">Batal</a>':'').'</form></div></div></div><div class="col-xl-8"><div class="card network-card"><div class="card-header"><h3 class="card-title">Pelanggan per ODP</h3><span class="badge badge-info">'.(int)scalar('SELECT COUNT(*) FROM network_customer_placements').' relasi</span></div><div class="card-body"><div class="table-wrap"><table class="table table-striped network-table"><thead><tr><th>Pelanggan</th><th>ODP / port</th><th>Drop cable</th><th>Status</th><th>Lokasi</th><th>Aksi</th></tr></thead><tbody>';
    $rows=qall('SELECT p.*,c.customer_code,c.name customer_name,c.address,c.latitude customer_lat,c.longitude customer_lng,n.node_code,n.name odp_name,n.latitude odp_lat,n.longitude odp_lng FROM network_customer_placements p JOIN customers c ON c.id=p.customer_id JOIN network_nodes n ON n.id=p.odp_id ORDER BY n.node_code,p.port_no');foreach($rows as $r){$maps=[];if($r['odp_lat']!==''&&$r['odp_lng']!=='')$maps[]='<a target="_blank" href="'.e(v3_google_maps_url($r['odp_lat'],$r['odp_lng'])).'">ODP</a>';if($r['customer_lat']!==''&&$r['customer_lng']!=='')$maps[]='<a target="_blank" href="'.e(v3_google_maps_url($r['customer_lat'],$r['customer_lng'])).'">Pelanggan</a>';echo '<tr><td><b>'.e($r['customer_code'].' · '.$r['customer_name']).'</b><small>'.e($r['address']).'</small></td><td><b>'.e($r['node_code']).' / Port '.(int)$r['port_no'].'</b><small>'.e($r['odp_name']).'</small></td><td>'.e($r['drop_cable_label']?:'-').'<small>'.e($r['installed_at']?:'-').'</small></td><td>'.v3_network_status_badge($r['status']).'</td><td>'.($maps?implode(' · ',$maps):'<span class="text-muted">Belum ada koordinat</span>').'</td><td><a class="btn btn-info btn-sm" href="'.page_url('network-customers',['edit'=>$r['id']]).'">Edit</a> '.v3_network_delete_form('network_delete_customer_placement',$r['id'],'Lepas').'</td></tr>';}if(!$rows)echo '<tr><td colspan="6" class="text-center text-muted">Belum ada pelanggan yang ditempatkan ke ODP.</td></tr>';echo '</tbody></table></div></div></div></div></div>';
}
function v3_network_render($page){
    require_non_crew();
    if($page==='network-dashboard') return v3_network_render_dashboard();
    if(in_array($page,['network-odc','network-odp','network-jc'],true)) return v3_network_render_nodes($page);
    if($page==='network-cables') return v3_network_render_cables();
    if($page==='network-splices') return v3_network_render_splices();
    if($page==='network-customers') return v3_network_render_customers();
}
